insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Long Beach', 'long-beach', 'beaches', 'San Vicente''s signature coastline: a 14-kilometre sweep of golden sand with gentle water, coconut edges, and long stretches that still feel undeveloped compared with busier Palawan towns.', 'The longest white-sand beach in the Philippines, minutes from town.', 10.4962, 119.2607, 'Poblacion – New Agutaya', '/images/san-vicente-long-beach.jpg', 4.9, null, 'Sunrise for quiet, late afternoon for color', 'Nov–May', 10, null, array['swimming','sunset','walking','quiet'], true, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Itaytay Beach', 'itaytay-beach', 'beaches', 'The Port Barton village beachfront: a calm bay lined with outrigger boats, beach bars, and simple restaurants. The easiest place in San Vicente to swim, eat, and watch the boats come in without going anywhere.', 'Calm bay swimming right off the village, with food steps away.', 10.4581, 119.2109, 'Port Barton', '/images/san-vicente-port-barton.jpg', 4.6, null, 'Morning before boats depart, or golden hour', 'Dec–May', 80, null, array['swimming','boats','village','easy'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('White Beach', 'white-beach-port-barton', 'beaches', 'A quiet cove south of Port Barton village, reached by a short scenic walk or a five-minute boat ride. Fine pale sand, shady palms, and far fewer people than the village beach.', 'A quieter cove a short walk from Port Barton village.', 10.4443, 119.2172, 'Port Barton', null, 4.7, null, 'Midday when the shallows glow', 'Dec–May', 95, '15 min walk or 5 min boat from Port Barton', array['quiet','swimming','cove','walk'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Alimanguan Beach', 'alimanguan-beach', 'beaches', 'The wilder northern end of San Vicente''s coast near Alimanguan village. Open surf-brushed sand, fishing boats, and almost nobody around — a real edge-of-the-map feeling.', 'Wide, empty northern sand for travelers who want space.', 10.5836, 119.3242, 'Alimanguan', null, 4.5, null, 'Late afternoon', 'Nov–May', 35, null, array['quiet','wild','walking','local'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Boayan Island', 'boayan-island', 'islands', 'A remote island off San Vicente''s northwest coast with clear water, forested hills, and small coves. A frontier feeling for travelers who want a quieter island escape than the tour circuits.', 'The remote island escape — clear coves, almost no crowds.', 10.55, 119.09, 'New Canipo', '/images/san-vicente-boayan.jpg', 4.7, null, 'Full-day trip, leave by 8am', 'Mar–May', null, 'By arranged boat from Poblacion or New Canipo', array['remote','snorkeling','day-trip','boat'], true, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('German Island', 'german-island', 'islands', 'A small island stop on the classic Port Barton tour, known for clear shallows, an easy snorkeling reef, and sandbars at low tide. Turtles are often sighted nearby — keep your distance and never touch.', 'Clear shallows and turtle sightings on the classic boat route.', 10.4586, 119.0705, 'Port Barton', '/images/island-boats-aerial.jpg', 4.6, null, 'Morning tours get the calmest water', 'Dec–May', null, '30–45 min by boat from Port Barton', array['snorkeling','turtles','tour','sandbar'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Inaladelan Island', 'inaladelan-island', 'islands', 'A polished island stop from Port Barton with bright sand, clear water, hammocks, and an easy picnic atmosphere. Camping overnight is possible with the caretakers — one of Palawan''s simplest island-sleep experiences.', 'Bright sand, hammocks, and the easiest island picnic day.', 10.4643, 119.0447, 'Port Barton', '/images/kayak-lagoon.jpg', 4.7, null, 'Any clear day; overnight camping for stargazers', 'Dec–May', null, 'By boat from Port Barton, usually on tours', array['picnic','camping','snorkeling','tour'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Exotic Island Sandbar', 'exotic-island-sandbar', 'islands', 'A slim sandbar island between Port Barton and the open sea that appears and shrinks with the tide. Boats stop for photos, quick swims, and the strange pleasure of standing on sand in the middle of the sea.', 'Stand on a sandbar in the middle of the sea at low tide.', 10.4306, 119.1264, 'Port Barton', null, 4.5, null, 'Low tide — ask your boatman to time it', 'Dec–May', null, 'Island-hopping stop from Port Barton', array['sandbar','photos','tour','tide'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Pamuayan Falls', 'pamuayan-falls', 'nature', 'A freshwater waterfall near Port Barton reached by a short inland ride and a forest walk. A cool plunge pool under the drop — ideal when you need a break from saltwater and beach heat.', 'A cool freshwater plunge 25 minutes from Port Barton.', 10.4808, 119.2383, 'Pamuayan', '/images/san-vicente-waterfalls.jpg', 4.5, null, 'After light rain for stronger flow', 'Year-round', 60, '25 min from Port Barton by trail or motorbike', array['waterfall','freshwater','hike','shade'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Bato ni Ningning', 'bato-ni-ningning', 'nature', 'A scenic rock viewpoint above the coast where Long Beach, the green hills, and the scale of the municipality reveal themselves. The classic San Vicente panorama shot.', 'The viewpoint that shows you all 14 km of Long Beach at once.', 10.5634, 119.3092, 'Sto. Niño', null, 4.6, null, 'Late afternoon for soft light', 'Nov–May', 35, null, array['viewpoint','photos','sunset','short-hike'], true, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Little Baguio Falls', 'little-baguio-falls', 'nature', 'A tiered jungle waterfall inland from the Poblacion side, with cool pools and a forest picnic feel. Less visited than Pamuayan — bring grippy sandals and pack out everything you bring in.', 'Tiered jungle pools on the quiet inland side.', 10.5089, 119.3306, 'Kemdeng', null, 4.4, null, 'Morning, before day-trip heat', 'Jun–Nov flows strongest', 30, null, array['waterfall','jungle','swimming','quiet'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('San Vicente Poblacion', 'san-vicente-poblacion', 'culture', 'The practical center of San Vicente: transport terminals, the public market, municipal services, small eateries, and everyday local life away from the island-hopping crowds. Every SANVIC travel time is measured from here.', 'The town center — market, transport, and everyday Palawan life.', 10.5318, 119.2822, 'Poblacion', null, 4.3, null, 'Morning market hours', 'Year-round', 0, null, array['market','transport','local-life','supplies'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Port Barton Village', 'port-barton-village', 'culture', 'A relaxed fishing village turned traveler hub inside San Vicente. Sandy lanes, island-hopping boats, beachfront cafés, and a slower rhythm made for unhurried travelers. Bring cash — ATMs are unreliable.', 'San Vicente''s laid-back traveler village and boat-tour base.', 10.4102, 119.1771, 'Port Barton', '/images/san-vicente-port-barton.jpg', 4.8, null, 'Golden hour on the beachfront', 'Dec–May', 80, null, array['village','boats','nightlife-lite','base'], true, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Poblacion Market Eateries', 'poblacion-market-eateries', 'food', 'The cluster of carinderias and grill stalls around the public market. Grilled fish straight off the boats, silog breakfasts, and the cheapest honest meal in the municipality. Cash only, lunch sells out early.', 'Grilled catch-of-the-day beside the market for pocket change.', 10.5301, 119.2835, 'Poblacion', '/images/street-food-skewers.jpg', 4.4, 1, 'Lunch, before 1pm', 'Year-round', 0, null, array['local-food','seafood','budget','cash-only'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Long Beach Grill Row', 'long-beach-grill-row', 'food', 'The strip of beachfront grills and family restaurants along the New Agutaya stretch of Long Beach. Kinilaw, grilled squid, halo-halo, and cold drinks with your feet still in the sand.', 'Fresh kinilaw and grilled squid with sand under your feet.', 10.5122, 119.2704, 'New Agutaya', null, 4.5, 2, 'Sunset dinner', 'Nov–May', 8, null, array['seafood','beachfront','sunset','dinner'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Jambalaya Café', 'jambalaya-cafe', 'food', 'A Port Barton beachfront staple for big breakfasts, fruit shakes, and relaxed dinners. One of the village''s most dependable kitchens after a day on the boats.', 'Port Barton''s dependable beachfront kitchen — great after tours.', 10.4576, 119.2119, 'Port Barton', null, 4.6, 2, 'Breakfast before tours, dinner after', 'Year-round', 80, null, array['breakfast','shakes','beachfront','traveler-favorite'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Long Beach Garden Stays', 'long-beach-garden-stays', 'stays', 'A quiet cluster of garden cottages and small resorts along the central Long Beach stretch. Direct beach access, hammocks, and real silence at night — the anti-resort resort experience.', 'Garden cottages with direct access to the empty 14-km beach.', 10.5049, 119.2652, 'New Agutaya', null, 4.6, 2, 'Book ahead Dec–Apr', 'Nov–May', 9, null, array['beachfront','quiet','cottages','couples'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Port Barton Bayfront Stays', 'port-barton-bayfront-stays', 'stays', 'Beachfront guesthouses and small resorts on Itaytay Beach, steps from the boats. The social base: easy tours, easy food, easy sunsets. Book early in high season.', 'Wake up steps from the boats and the bay.', 10.4589, 119.2101, 'Port Barton', null, 4.5, 2, 'Book ahead Dec–Apr', 'Dec–May', 80, null, array['beachfront','social','tours','budget-to-mid'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Poblacion Café Corner', 'poblacion-cafe-corner', 'work', 'The small set of cafés around Poblacion with dependable signal, real espresso, and power outlets. San Vicente''s best bet for a focused laptop morning before an afternoon on Long Beach.', 'Espresso, outlets, and the town''s steadiest signal.', 10.5296, 119.2811, 'Poblacion', null, 4.2, 2, 'Weekday mornings', 'Year-round', 0, null, array['wifi','coffee','outlets','aircon'], false, true);
insert into public.places (name, slug, category, description, short_reason, latitude, longitude, barangay, image_url, rating, price_level, best_time, best_season, travel_minutes_from_poblacion, travel_note, tags, is_featured, is_active) values ('Port Barton Garden Cafés', 'port-barton-garden-cafes', 'work', 'Shaded garden cafés a street back from Itaytay Beach where nomads settle in with smoothie bowls and laptops. Signal is decent, power can flicker — save often, swim at lunch.', 'Garden-shade laptop mornings, thirty steps from the sea.', 10.4571, 119.2131, 'Port Barton', null, 4.3, 2, 'Mornings before heat', 'Dec–May', 80, null, array['wifi','nomad','garden','smoothies'], false, true);
