insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'german-island'), 'morning', 'Island trip worth booking', 'Morning boats get the calmest water for the turtle reef. Book at the beachfront kiosks today.', 2, 'clear', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'white-beach-port-barton'), 'midday', 'Best beach right now', 'The shallows glow brightest at midday, and the palms give real shade when the sun peaks.', 1, 'clear', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'pamuayan-falls'), 'midday', 'Beat the heat', 'A cold freshwater plunge under forest shade — the smartest place to be at peak heat.', 2, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = null), 'midday', 'Lunch like a local', 'Grilled catch-of-the-day beside the market — the good stuff sells out by 1pm.', 2, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'long-beach'), 'afternoon', 'Golden-hour walk', 'Start near Poblacion and walk south — the light softens and the beach empties as you go.', 2, 'clear', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'bato-ni-ningning'), 'afternoon', 'The panorama shot', 'Late-afternoon light turns the whole coastline gold from up here. Allow 35 minutes to get up.', 1, 'clear', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'long-beach-grill-row'), 'afternoon', 'Early dinner spot', 'Claim a beachfront table before the sunset crowd; the kinilaw is made to order.', 3, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'long-beach'), 'sunset', 'Best sunset spot tonight', 'The west-facing sand line means an unobstructed horizon sunset almost anywhere on the beach.', 1, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'bato-ni-ningning'), 'sunset', 'Sunset from above', 'Watch the sun drop behind Boayan from the rock — bring a light for the way down.', 2, 'clear', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'long-beach-grill-row'), 'sunset', 'Dinner with the show', 'Grilled squid and a cold drink while the sky does its thing 20 meters away.', 2, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'port-barton-village'), 'evening', 'Evenings with a pulse', 'Beach bonfires and low-key beachfront bars — the closest San Vicente gets to nightlife.', 1, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'long-beach-garden-stays'), 'evening', 'Where to sleep well', 'Garden cottages on the quiet stretch — fall asleep to waves, not karaoke.', 2, 'any', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'poblacion-cafe-corner'), 'rainy', 'Rainy-day base', 'Dry, caffeinated, connected. Wait out the cell here — coastal rain usually passes within hours.', 1, 'rain', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'pamuayan-falls'), 'rainy', 'After the rain', 'Light rain feeds the falls — go once it eases for the strongest flow of the week. Skip during heavy rain.', 2, 'rain', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = null), 'rainy', 'Comfort food weather', 'Hot lugaw and fresh lumpia under the market roof while it pours.', 3, 'rain', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'boayan-island'), 'any', 'Plan ahead: the remote one', 'Boayan needs an arranged boat and a calm-sea day — worth lining up two days out.', 5, 'clear', true);
insert into public.recommendations (place_id, context_type, title, reason, priority, weather_condition, is_active) values ((select id from public.places where slug = 'port-barton-bayfront-stays'), 'any', 'Stay recommendation', 'Bayfront rooms steps from the boats — the easy base if tours are your plan.', 6, 'any', true);
insert into public.local_updates (title, body, category, location, severity, source, created_at, valid_until) values
('Long Beach: calm and clear', 'Gentle water on the central stretch this morning, light onshore breeze after lunch. Good swimming until mid-afternoon; the New Agutaya section is quietest.', 'beach', 'Long Beach', 'good', 'SANVIC conditions desk', now() - interval '2 hours', now() + interval '10 hours'),
('Tonight''s sunset window', 'Sun drops around 6:05pm with a mostly open western horizon. Best positions: anywhere on Long Beach, or Bato ni Ningning if you leave Poblacion by 4:45pm.', 'sunset', 'West coast', 'info', 'SANVIC conditions desk', now() - interval '3 hours', now() + interval '8 hours'),
('Island hopping: boats running', 'Port Barton tours departing normally. Morning departures recommended — afternoon chop has been picking up near German Island this week. Bring cash for environmental fees.', 'island-hopping', 'Port Barton', 'good', 'Boat operators'' association', now() - interval '5 hours', now() + interval '20 hours'),
('Poblacion–Port Barton road: clear', 'The inland road is dry and passable end to end. Vans running on schedule, about 1h20 door to door. Last van back to Poblacion leaves Port Barton at 4pm.', 'travel', 'San Vicente–Port Barton road', 'info', 'Transport terminal', now() - interval '8 hours', now() + interval '30 hours'),
('Food tip: tuna panga at the market grills', 'Boats came in heavy with tuna this week — the market grill stalls have panga (jaw) at local prices through the weekend. Lunch crowd clears it by 1pm.', 'food', 'Poblacion market', 'good', 'Local contributor', now() - interval '22 hours', now() + interval '60 hours'),
('Quiet right now: Alimanguan stretch', 'The northern beaches are near-empty on weekdays this month. If you want the sand to yourself, this is the window before the holiday season starts.', 'tip', 'Alimanguan', 'info', 'SANVIC conditions desk', now() - interval '30 hours', null),
('Pamuayan Falls flowing well', 'This week''s evening rain has the falls at their best flow of the month. Trail is a little slick in two spots — wear grippy footwear.', 'tip', 'Pamuayan', 'good', 'Local guides', now() - interval '40 hours', null),
('Heads up: barangay fiesta preparations', 'New Agutaya starts fiesta preparations next week — expect evening music near the barangay hall and busier eateries. Great time to try lechon if your trip overlaps.', 'event', 'New Agutaya', 'info', 'Barangay bulletin', now() - interval '50 hours', null);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Poblacion', 'poblacion', 'Municipal center: market, transport terminals, airport, and Long Beach access.', 10.5318, 119.2822, true, 1, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('New Agutaya', 'new-agutaya', 'Heart of the Long Beach stretch — garden stays and beachfront grills.', 10.5122, 119.266, true, 2, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('San Isidro', 'san-isidro', 'Inland farms and hills northeast of the town center.', 10.567, 119.3187, true, 3, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Alimanguan', 'alimanguan', 'Fishing village with the wild, empty northern beaches.', 10.59, 119.33, true, 4, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Santo Niño', 'santo-nino', 'Quiet coastal barangay between Alimanguan and New Canipo.', 10.6506, 119.3348, true, 5, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('New Canipo', 'new-canipo', 'Northern coast and the jump-off toward Boayan Island.', 10.6969, 119.3078, true, 6, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Binga', 'binga', 'San Vicente''s northernmost barangay.', 10.7612, 119.3144, true, 7, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Kemdeng', 'kemdeng', 'Between Poblacion and Port Barton — waterfalls and inland trails.', 10.4797, 119.2545, true, 8, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Port Barton', 'port-barton', 'The traveler village: island-hopping boats, bay beaches, café life.', 10.46, 119.195, true, 9, true);
insert into public.barangays (name, slug, description, latitude, longitude, label_visible, sort_order, is_active) values ('Caruray', 'caruray', 'Remote southwestern coast and islands, bordering Puerto Princesa.', 10.3701, 119.0155, true, 10, true);
